#include <algorithm>

long long solve(std::vector<long long> nums, long long k) {
    std::unordered_map<long long, long long> prefix_mod;
    prefix_mod[0] = 0; // Initial state: sum 0 with 0 mod k
    long long total_sum = 0;
    long long min_sum = std::numeric_limits<long long>::max();

    for (long long num : nums) {
        total_sum += num;
        long long current_mod = total_sum % k;
        // If current_mod is 0, we can remove the entire array so far
        if (current_mod == 0) {
            min_sum = std::min(min_sum, total_sum);
        }
        // Check if we have seen this mod before
        if (prefix_mod.find(current_mod) != prefix_mod.end()) {
            long long prev_sum = prefix_mod[current_mod];
            min_sum = std::min(min_sum, total_sum - prev_sum);
        } else {
            prefix_mod[current_mod] = total_sum;
        }
    }

    return min_sum;
}
