long long solve(std::vector<long long> nums, long long k) {
    long long total_sum = 0;
    std::unordered_map<long long, long long> mod_count;
    mod_count[0] = 1; // To handle cases where the prefix sum is divisible by k

    long long current_sum = 0;
    for (long long num : nums) {
        current_sum += num;
        long long mod = current_sum % k;
        mod = (mod + k) % k; // Ensure mod is non-negative
        mod_count[mod]++;
        total_sum += num;
    }

    // Try to remove as many subarrays as possible with sum divisible by k
    for (auto& [mod, count] : mod_count) {
        if (mod == 0) {
            // If the mod is 0, we can remove the entire array
            return 0;
        }
        // For other mods, we can remove a subarray with this mod
        total_sum -= count * mod;
    }

    return total_sum;
}
